defmodule Waw.Logo do
  @moduledoc """
    Un logo de Tag-IP.
  """

  use Phoenix.Component

  def list do
    [
      "tag-ip",
      "track",
      "park_blue",
      "park_black",
      "park_white",
      "park_with_title_white",
      "park_with_title_black"
    ]
  end

  attr(:name, :string,
    doc: "Logo name of Tag-IP.",
    default: "tag-ip",
    values: [
      "tag-ip",
      "track",
      "park_blue",
      "park_black",
      "park_white",
      "park_with_title_white",
      "park_with_title_black",
      "forms"
    ]
  )

  @doc """
  Afficher logo de Tag-IP.

  ## Usage

  ```
  <.logo name={@logo} />
  ```
  """

  def logo(%{name: "tag-ip"} = assigns), do: tagip(assigns)
  def logo(%{name: "track"} = assigns), do: track(assigns)
  def logo(%{name: "park_blue"} = assigns), do: park_blue(assigns)
  def logo(%{name: "park_black"} = assigns), do: park_black(assigns)
  def logo(%{name: "park_white"} = assigns), do: park_white(assigns)

  def logo(%{name: "park_with_title_white"} = assigns),
    do: park_with_title_white(assigns)

  def logo(%{name: "park_with_title_black"} = assigns),
    do: park_with_title_black(assigns)

  def logo(%{name: "park_with_title_blue"} = assigns),
    do: park_with_title_blue(assigns)

  def logo(assigns), do: tagip(assigns)

